@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Home - University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Explore our departments, browse courses, and submit your enrollment request.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                    <a href="courses/@course.Id" class="card-link">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in _departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="card-link">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" id="search" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select id="departmentId" name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (_courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in _courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        _courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found") - University Course Catalog</PageTitle>

@if (_course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.CourseCode</li>
        </ol>
    </nav>

    <h1>@_course.Title</h1>
    <p class="text-muted fs-5">@_course.CourseCode &middot; @_course.DepartmentName</p>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@_course.Description</p>

            <h2 class="mt-4">Instructor</h2>
            <h5>@_course.InstructorName</h5>
            <p>@_course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <dl>
                        <dt>Credits</dt>
                        <dd>@_course.Credits</dd>
                        <dt>Schedule</dt>
                        <dd>@_course.Schedule</dd>
                        <dt>Department</dt>
                        <dd>@_course.DepartmentName</dd>
                    </dl>
                    <a href="enroll?courseId=@_course.Id" class="btn btn-primary w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit your enrollment request.</p>

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Request Submitted</h4>
        <p>Your enrollment request has been submitted successfully. You will receive confirmation via your university email.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required pattern="[A-Z0-9]{6,10}" placeholder="e.g., ABC12345" />
                    <div class="form-text">6-10 uppercase alphanumeric characters.</div>
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select id="courseId" name="Model.CourseId" class="form-select" required>
                        <option value="">-- Select a Course --</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode - @course.Title</option>
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> _courses = new();
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollment(Model);
        _submitted = true;
    }
}

